import React, { useState, useEffect } from 'react';
import { Upload, Search, FileText, Download, Eye, Plus, X, Edit2, Save, File, AlertCircle, CheckCircle } from 'lucide-react';

const EmployeeDocumentSystem = () => {
  const [activeTab, setActiveTab] = useState('upload');
  const [documents, setDocuments] = useState([]);
  const [employees, setEmployees] = useState([]);
  const [categories, setCategories] = useState([]);
  const [templates, setTemplates] = useState([]);
  const [searchResults, setSearchResults] = useState([]);
  const [notifications, setNotifications] = useState([]);

  // Form states
  const [uploadForm, setUploadForm] = useState({
    employeeId: '',
    documentType: '',
    issueDate: '',
    expiryDate: '',
    remarks: '',
    file: null
  });

  const [searchForm, setSearchForm] = useState({
    employeeName: '',
    employeeId: '',
    storeLocation: '',
    documentType: '',
    expiryDateFrom: '',
    expiryDateTo: ''
  });

  const [templateForm, setTemplateForm] = useState({
    name: '',
    content: '',
    variables: []
  });

  const [selectedEmployee, setSelectedEmployee] = useState(null);
  const [previewDoc, setPreviewDoc] = useState(null);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [newCategory, setNewCategory] = useState('');
  const [showTemplateEditor, setShowTemplateEditor] = useState(false);
  const [editingTemplate, setEditingTemplate] = useState(null);

  // Initialize demo data
  useEffect(() => {
    initializeDemoData();
  }, []);

  const initializeDemoData = () => {
    const demoEmployees = [
      { id: 'EMP001', name: 'Rajesh Kumar', store: 'Station Alpha', role: 'Manager' },
      { id: 'EMP002', name: 'Priya Singh', store: 'Station Beta', role: 'Cashier' },
      { id: 'EMP003', name: 'Amit Patel', store: 'Store Gamma', role: 'Supervisor' },
      { id: 'EMP004', name: 'Sneha Reddy', store: 'Station Delta', role: 'Attendant' },
      { id: 'EMP005', name: 'Vikram Sharma', store: 'Store Epsilon', role: 'Sales Associate' }
    ];

    const demoCategories = [
      'ID Proof',
      'Driving License',
      'Medical Certificate',
      'Training Certificate',
      'Employment Contract',
      'Educational Certificate',
      'Address Proof',
      'Police Verification'
    ];

    const demoTemplates = [
      {
        id: 'T001',
        name: 'Warning Letter',
        content: `Date: {{Date}}

To,
{{EmployeeName}}
{{Store}}

Subject: Warning Letter

Dear {{EmployeeName}},

This letter serves as a formal warning regarding [reason]. We expect immediate improvement in your conduct/performance.

Further violation may result in disciplinary action.

Regards,
HR Department`,
        variables: ['Date', 'EmployeeName', 'Store']
      },
      {
        id: 'T002',
        name: 'Offer Letter',
        content: `Date: {{Date}}

Dear {{EmployeeName}},

We are pleased to offer you the position of {{Position}} at {{Store}}.

Your employment will commence on {{JoiningDate}}.

Salary: {{Salary}}
Reporting To: {{ReportingManager}}

Please confirm your acceptance by signing below.

Sincerely,
HR Department`,
        variables: ['Date', 'EmployeeName', 'Position', 'Store', 'JoiningDate', 'Salary', 'ReportingManager']
      }
    ];

    const demoDocs = [
      {
        id: 'DOC001',
        employeeId: 'EMP001',
        employeeName: 'Rajesh Kumar',
        store: 'Station Alpha',
        documentType: 'Driving License',
        issueDate: '2020-01-15',
        expiryDate: '2025-01-15',
        uploadDate: '2024-11-01',
        fileName: 'rajesh_license.pdf',
        status: 'valid',
        version: 1,
        uploadedBy: 'Admin'
      },
      {
        id: 'DOC002',
        employeeId: 'EMP002',
        employeeName: 'Priya Singh',
        store: 'Station Beta',
        documentType: 'Medical Certificate',
        issueDate: '2024-10-01',
        expiryDate: '2025-01-01',
        uploadDate: '2024-10-05',
        fileName: 'priya_medical.pdf',
        status: 'expiring',
        version: 1,
        uploadedBy: 'HR Staff'
      }
    ];

    setEmployees(demoEmployees);
    setCategories(demoCategories);
    setTemplates(demoTemplates);
    setDocuments(demoDocs);
    setSearchResults(demoDocs);
  };

  const showNotification = (message, type = 'success') => {
    const id = Date.now();
    setNotifications(prev => [...prev, { id, message, type }]);
    setTimeout(() => {
      setNotifications(prev => prev.filter(n => n.id !== id));
    }, 3000);
  };

  const handleFileUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      const validTypes = ['application/pdf', 'image/jpeg', 'image/png', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'];
      if (validTypes.includes(file.type)) {
        setUploadForm({ ...uploadForm, file });
      } else {
        showNotification('Invalid file type. Please upload PDF, DOCX, JPG, or PNG', 'error');
      }
    }
  };

  const handleDocumentUpload = () => {
    if (!uploadForm.employeeId || !uploadForm.documentType || !uploadForm.file) {
      showNotification('Please fill all required fields', 'error');
      return;
    }

    const employee = employees.find(e => e.id === uploadForm.employeeId);
    const newDoc = {
      id: `DOC${String(documents.length + 1).padStart(3, '0')}`,
      employeeId: uploadForm.employeeId,
      employeeName: employee.name,
      store: employee.store,
      documentType: uploadForm.documentType,
      issueDate: uploadForm.issueDate,
      expiryDate: uploadForm.expiryDate,
      uploadDate: new Date().toISOString().split('T')[0],
      fileName: uploadForm.file.name,
      status: getDocStatus(uploadForm.expiryDate),
      version: 1,
      uploadedBy: 'Current User',
      remarks: uploadForm.remarks
    };

    setDocuments([...documents, newDoc]);
    setSearchResults([...searchResults, newDoc]);
    showNotification('Document uploaded successfully!');

    setUploadForm({
      employeeId: '',
      documentType: '',
      issueDate: '',
      expiryDate: '',
      remarks: '',
      file: null
    });
  };

  const getDocStatus = (expiryDate) => {
    if (!expiryDate) return 'valid';
    const today = new Date();
    const expiry = new Date(expiryDate);
    const daysUntilExpiry = Math.floor((expiry - today) / (1000 * 60 * 60 * 24));

    if (daysUntilExpiry < 0) return 'expired';
    if (daysUntilExpiry <= 30) return 'expiring';
    return 'valid';
  };

  const handleSearch = () => {
    let results = documents;

    if (searchForm.employeeName) {
      results = results.filter(doc => 
        doc.employeeName.toLowerCase().includes(searchForm.employeeName.toLowerCase())
      );
    }
    if (searchForm.employeeId) {
      results = results.filter(doc => doc.employeeId === searchForm.employeeId);
    }
    if (searchForm.storeLocation) {
      results = results.filter(doc => 
        doc.store.toLowerCase().includes(searchForm.storeLocation.toLowerCase())
      );
    }
    if (searchForm.documentType) {
      results = results.filter(doc => doc.documentType === searchForm.documentType);
    }
    if (searchForm.expiryDateFrom) {
      results = results.filter(doc => 
        doc.expiryDate && doc.expiryDate >= searchForm.expiryDateFrom
      );
    }
    if (searchForm.expiryDateTo) {
      results = results.filter(doc => 
        doc.expiryDate && doc.expiryDate <= searchForm.expiryDateTo
      );
    }

    setSearchResults(results);
    showNotification(`Found ${results.length} document(s)`);
  };

  const handleAddCategory = () => {
    if (newCategory && !categories.includes(newCategory)) {
      setCategories([...categories, newCategory]);
      showNotification('Category added successfully!');
      setNewCategory('');
      setShowCategoryModal(false);
    }
  };

  const handleSaveTemplate = () => {
    if (!templateForm.name || !templateForm.content) {
      showNotification('Please fill all template fields', 'error');
      return;
    }

    const variables = [...templateForm.content.matchAll(/{{(\w+)}}/g)].map(m => m[1]);

    if (editingTemplate) {
      setTemplates(templates.map(t => 
        t.id === editingTemplate.id 
          ? { ...t, name: templateForm.name, content: templateForm.content, variables }
          : t
      ));
      showNotification('Template updated successfully!');
    } else {
      const newTemplate = {
        id: `T${String(templates.length + 1).padStart(3, '0')}`,
        name: templateForm.name,
        content: templateForm.content,
        variables
      };
      setTemplates([...templates, newTemplate]);
      showNotification('Template created successfully!');
    }

    setTemplateForm({ name: '', content: '', variables: [] });
    setShowTemplateEditor(false);
    setEditingTemplate(null);
  };

  const handleGenerateLetter = (template) => {
    if (!selectedEmployee) {
      showNotification('Please select an employee first', 'error');
      return;
    }

    let content = template.content;
    content = content.replace(/{{EmployeeName}}/g, selectedEmployee.name);
    content = content.replace(/{{Store}}/g, selectedEmployee.store);
    content = content.replace(/{{Date}}/g, new Date().toLocaleDateString());
    content = content.replace(/{{Position}}/g, selectedEmployee.role);

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${template.name}_${selectedEmployee.name}.txt`;
    a.click();

    showNotification('Letter generated and downloaded!');
  };

  const getStatusBadge = (status) => {
    const badges = {
      valid: 'bg-green-100 text-green-800',
      expiring: 'bg-orange-100 text-orange-800',
      expired: 'bg-red-100 text-red-800'
    };
    return badges[status] || badges.valid;
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Notifications */}
      <div className="fixed top-4 right-4 z-50 space-y-2">
        {notifications.map(notif => (
          <div key={notif.id} className={`flex items-center gap-2 px-4 py-3 rounded-lg shadow-lg ${
            notif.type === 'error' ? 'bg-red-500' : 'bg-green-500'
          } text-white`}>
            {notif.type === 'error' ? <AlertCircle size={20} /> : <CheckCircle size={20} />}
            {notif.message}
          </div>
        ))}
      </div>

      {/* Header */}
      <div className="bg-blue-600 text-white p-6 shadow-lg">
        <h1 className="text-3xl font-bold">Employee Document Management System</h1>
        <p className="text-blue-100 mt-2">Centralized document management across 20 stores</p>
      </div>

      {/* Navigation */}
      <div className="bg-white shadow">
        <div className="max-w-7xl mx-auto px-4">
          <div className="flex space-x-8">
            {[
              { id: 'upload', label: 'Document Upload', icon: Upload },
              { id: 'search', label: 'Search & Retrieve', icon: Search },
              { id: 'templates', label: 'Letter Templates', icon: FileText }
            ].map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`flex items-center gap-2 px-4 py-4 border-b-2 transition-colors ${
                  activeTab === tab.id
                    ? 'border-blue-600 text-blue-600'
                    : 'border-transparent text-gray-600 hover:text-gray-900'
                }`}
              >
                <tab.icon size={20} />
                {tab.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="max-w-7xl mx-auto px-4 py-8">
        {/* Document Upload Tab */}
        {activeTab === 'upload' && (
          <div className="space-y-6">
            <div className="bg-white rounded-lg shadow p-6">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-800">Upload Document</h2>
                <button
                  onClick={() => setShowCategoryModal(true)}
                  className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
                >
                  <Plus size={20} />
                  Add Category
                </button>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Employee *
                  </label>
                  <select
                    value={uploadForm.employeeId}
                    onChange={(e) => setUploadForm({ ...uploadForm, employeeId: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  >
                    <option value="">Select Employee</option>
                    {employees.map(emp => (
                      <option key={emp.id} value={emp.id}>
                        {emp.id} - {emp.name} ({emp.store})
                      </option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Document Type *
                  </label>
                  <select
                    value={uploadForm.documentType}
                    onChange={(e) => setUploadForm({ ...uploadForm, documentType: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  >
                    <option value="">Select Type</option>
                    {categories.map(cat => (
                      <option key={cat} value={cat}>{cat}</option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Issue Date
                  </label>
                  <input
                    type="date"
                    value={uploadForm.issueDate}
                    onChange={(e) => setUploadForm({ ...uploadForm, issueDate: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Expiry Date
                  </label>
                  <input
                    type="date"
                    value={uploadForm.expiryDate}
                    onChange={(e) => setUploadForm({ ...uploadForm, expiryDate: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  />
                </div>

                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Remarks
                  </label>
                  <textarea
                    value={uploadForm.remarks}
                    onChange={(e) => setUploadForm({ ...uploadForm, remarks: e.target.value })}
                    rows="3"
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    placeholder="Additional notes..."
                  />
                </div>

                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Upload File * (PDF, DOCX, JPG, PNG)
                  </label>
                  <div className="border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:border-blue-500 transition-colors">
                    <input
                      type="file"
                      onChange={handleFileUpload}
                      accept=".pdf,.docx,.jpg,.jpeg,.png"
                      className="hidden"
                      id="file-upload"
                    />
                    <label htmlFor="file-upload" className="cursor-pointer">
                      <Upload className="mx-auto mb-2 text-gray-400" size={40} />
                      <p className="text-sm text-gray-600">
                        {uploadForm.file ? uploadForm.file.name : 'Click to upload or drag and drop'}
                      </p>
                    </label>
                  </div>
                </div>
              </div>

              <button
                onClick={handleDocumentUpload}
                className="mt-6 w-full bg-blue-600 text-white py-3 rounded-lg hover:bg-blue-700 font-semibold"
              >
                Upload Document
              </button>
            </div>

            {/* Version History */}
            <div className="bg-white rounded-lg shadow p-6">
              <h3 className="text-xl font-bold text-gray-800 mb-4">Recent Uploads</h3>
              <div className="space-y-3">
                {documents.slice(-5).reverse().map(doc => (
                  <div key={doc.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-lg">
                    <div className="flex items-center gap-4">
                      <File className="text-blue-600" size={24} />
                      <div>
                        <p className="font-semibold">{doc.fileName}</p>
                        <p className="text-sm text-gray-600">{doc.employeeName} - {doc.documentType}</p>
                      </div>
                    </div>
                    <span className={`px-3 py-1 rounded-full text-sm font-semibold ${getStatusBadge(doc.status)}`}>
                      {doc.status}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* Search & Retrieve Tab */}
        {activeTab === 'search' && (
          <div className="space-y-6">
            <div className="bg-white rounded-lg shadow p-6">
              <h2 className="text-2xl font-bold text-gray-800 mb-6">Search Documents</h2>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
                <input
                  type="text"
                  placeholder="Employee Name"
                  value={searchForm.employeeName}
                  onChange={(e) => setSearchForm({ ...searchForm, employeeName: e.target.value })}
                  className="px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                />

                <select
                  value={searchForm.employeeId}
                  onChange={(e) => setSearchForm({ ...searchForm, employeeId: e.target.value })}
                  className="px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                >
                  <option value="">All Employees</option>
                  {employees.map(emp => (
                    <option key={emp.id} value={emp.id}>{emp.id} - {emp.name}</option>
                  ))}
                </select>

                <input
                  type="text"
                  placeholder="Store Location"
                  value={searchForm.storeLocation}
                  onChange={(e) => setSearchForm({ ...searchForm, storeLocation: e.target.value })}
                  className="px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                />

                <select
                  value={searchForm.documentType}
                  onChange={(e) => setSearchForm({ ...searchForm, documentType: e.target.value })}
                  className="px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                >
                  <option value="">All Document Types</option>
                  {categories.map(cat => (
                    <option key={cat} value={cat}>{cat}</option>
                  ))}
                </select>

                <input
                  type="date"
                  placeholder="Expiry From"
                  value={searchForm.expiryDateFrom}
                  onChange={(e) => setSearchForm({ ...searchForm, expiryDateFrom: e.target.value })}
                  className="px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                />

                <input
                  type="date"
                  placeholder="Expiry To"
                  value={searchForm.expiryDateTo}
                  onChange={(e) => setSearchForm({ ...searchForm, expiryDateTo: e.target.value })}
                  className="px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                />
              </div>

              <button
                onClick={handleSearch}
                className="w-full bg-blue-600 text-white py-3 rounded-lg hover:bg-blue-700 font-semibold flex items-center justify-center gap-2"
              >
                <Search size={20} />
                Search Documents
              </button>
            </div>

            {/* Search Results */}
            <div className="bg-white rounded-lg shadow p-6">
              <h3 className="text-xl font-bold text-gray-800 mb-4">
                Search Results ({searchResults.length})
              </h3>

              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead className="bg-gray-50">
                    <tr>
                      <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">Document ID</th>
                      <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">Employee</th>
                      <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">Store</th>
                      <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">Type</th>
                      <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">Expiry Date</th>
                      <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">Status</th>
                      <th className="px-4 py-3 text-left text-sm font-semibold text-gray-700">Actions</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-200">
                    {searchResults.map(doc => (
                      <tr key={doc.id} className="hover:bg-gray-50">
                        <td className="px-4 py-3 text-sm">{doc.id}</td>
                        <td className="px-4 py-3 text-sm">
                          <div>
                            <p className="font-semibold">{doc.employeeName}</p>
                            <p className="text-gray-500">{doc.employeeId}</p>
                          </div>
                        </td>
                        <td className="px-4 py-3 text-sm">{doc.store}</td>
                        <td className="px-4 py-3 text-sm">{doc.documentType}</td>
                        <td className="px-4 py-3 text-sm">{doc.expiryDate || 'N/A'}</td>
                        <td className="px-4 py-3">
                          <span className={`px-2 py-1 rounded-full text-xs font-semibold ${getStatusBadge(doc.status)}`}>
                            {doc.status}
                          </span>
                        </td>
                        <td className="px-4 py-3">
                          <div className="flex gap-2">
                            <button
                              onClick={() => setPreviewDoc(doc)}
                              className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg"
                              title="Preview"
                            >
                              <Eye size={18} />
                            </button>
                            <button
                              onClick={() => showNotification('Document downloaded!')}
                              className="p-2 text-green-600 hover:bg-green-50 rounded-lg"
                              title="Download"
                            >
                              <Download size={18} />
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}

        {/* Letter Templates Tab */}
        {activeTab === 'templates' && (
          <div className="space-y-6">
            <div className="bg-white rounded-lg shadow p-6">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-800">Letter Templates</h2>
                <button
                  onClick={() => {
                    setShowTemplateEditor(true);
                    setEditingTemplate(null);
                    setTemplateForm({ name: '', content: '', variables: [] });
                  }}
                  className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
                >
                  <Plus size={20} />
                  Create Template
                </button>
              </div>

              <div className="mb-6">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Select Employee for Auto-fill
                </label>
                <select
                  value={selectedEmployee?.id || ''}
                  onChange={(e) => setSelectedEmployee(employees.find(emp => emp.id === e.target.value))}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                >
                  <option value="">Select Employee</option>
                  {employees.map(emp => (
                    <option key={emp.id} value={emp.id}>
                      {emp.name} - {emp.id} ({emp.store})
                    </option>
                  ))}
                </select>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {templates.map(template => (
                  <div key={template.id} className="border border-gray-200 rounded-lg p-6">
                    <div className="flex justify-between items-start mb-4">
                      <div>
                        <h3 className="text-lg font-bold text-gray-800">{template.name}</h3>
                        <p className="text-sm text-gray-600">ID: {template.id}</p>
                      </div>
                      <button
                        onClick={() => {
                          setEditingTemplate(template);
                          setTemplateForm({ name: template.name, content: template.content, variables: template.variables });
                          setShowTemplateEditor(true);
                        }}
                        className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg"
                      >
                        <Edit2 size={18} />
                      </button>
                    </div>

                    <div className="bg-gray-50 p-4 rounded mb-4 text-sm font-mono whitespace-pre-wrap max-h-48 overflow-y-auto">
                      {template.content}
                    </div>

                    <div className="mb-4">
                      <p className="text-sm font-semibold text-gray-700 mb-2">Variables:</p>
                      <div className="flex flex-wrap gap-2">
                        {template.variables.map(variable => (
                          <span key={variable} className="px-2 py-1 bg-blue-100 text-blue-800 text-xs rounded">
                            {variable}
                          </span>
                        ))}
                      </div>
                    </div>

                    <button
                      onClick={() => handleGenerateLetter(template)}
                      className="w-full bg-green-600 text-white py-2 rounded-lg hover:bg-green-700 font-semibold flex items-center justify-center gap-2"
                    >
                      <Download size={18} />
                      Generate & Download
                    </button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Category Modal */}
      {showCategoryModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 w-full max-w-md">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-xl font-bold">Add New Category</h3>
              <button onClick={() => setShowCategoryModal(false)} className="text-gray-500 hover:text-gray-700">
                <X size={24} />
              </button>
            </div>

            <input
              type="text"
              value={newCategory}
              onChange={(e) => setNewCategory(e.target.value)}
              placeholder="Enter category name"
              className="w-full px-4 py-2 border border-gray-300 rounded-lg mb-4 focus:ring-2 focus:ring-blue-500"
            />

            <div className="mb-4">
              <p className="text-sm font-semibold text-gray-700 mb-2">Existing Categories:</p>
              <div className="flex flex-wrap gap-2">
                {categories.map(cat => (
                  <span key={cat} className="px-3 py-1 bg-gray-100 text-gray-700 text-sm rounded">
                    {cat}
                  </span>
                ))}
              </div>
            </div>

            <button
              onClick={handleAddCategory}
              className="w-full bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700 font-semibold"
            >
              Add Category
            </button>
          </div>
        </div>
      )}

      {/* Template Editor Modal */}
      {showTemplateEditor && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg p-6 w-full max-w-3xl max-h-[90vh] overflow-y-auto">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-xl font-bold">
                {editingTemplate ? 'Edit Template' : 'Create New Template'}
              </h3>
              <button onClick={() => setShowTemplateEditor(false)} className="text-gray-500 hover:text-gray-700">
                <X size={24} />
              </button>
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Template Name
                </label>
                <input
                  type="text"
                  value={templateForm.name}
                  onChange={(e) => setTemplateForm({ ...templateForm, name: e.target.value })}
                  placeholder="e.g., Warning Letter"
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Template Content
                </label>
                <p className="text-sm text-gray-600 mb-2">
                  Use variables like: {'{{EmployeeName}}'}, {'{{Store}}'}, {'{{Date}}'}, {'{{Position}}'}
                </p>
                <textarea
                  value={templateForm.content}
                  onChange={(e) => setTemplateForm({ ...templateForm, content: e.target.value })}
                  rows="15"
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg font-mono text-sm focus:ring-2 focus:ring-blue-500"
                  placeholder="Enter your letter template here..."
                />
              </div>

              <button
                onClick={handleSaveTemplate}
                className="w-full bg-blue-600 text-white py-3 rounded-lg hover:bg-blue-700 font-semibold flex items-center justify-center gap-2"
              >
                <Save size={20} />
                {editingTemplate ? 'Update Template' : 'Create Template'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Document Preview Modal */}
      {previewDoc && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg p-6 w-full max-w-4xl max-h-[90vh] overflow-y-auto">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-xl font-bold">Document Preview</h3>
              <button onClick={() => setPreviewDoc(null)} className="text-gray-500 hover:text-gray-700">
                <X size={24} />
              </button>
            </div>

            <div className="grid grid-cols-2 gap-4 mb-6 p-4 bg-gray-50 rounded-lg">
              <div>
                <p className="text-sm text-gray-600">Employee</p>
                <p className="font-semibold">{previewDoc.employeeName}</p>
              </div>
              <div>
                <p className="text-sm text-gray-600">Employee ID</p>
                <p className="font-semibold">{previewDoc.employeeId}</p>
              </div>
              <div>
                <p className="text-sm text-gray-600">Store</p>
                <p className="font-semibold">{previewDoc.store}</p>
              </div>
              <div>
                <p className="text-sm text-gray-600">Document Type</p>
                <p className="font-semibold">{previewDoc.documentType}</p>
              </div>
              <div>
                <p className="text-sm text-gray-600">Issue Date</p>
                <p className="font-semibold">{previewDoc.issueDate || 'N/A'}</p>
              </div>
              <div>
                <p className="text-sm text-gray-600">Expiry Date</p>
                <p className="font-semibold">{previewDoc.expiryDate || 'N/A'}</p>
              </div>
              <div>
                <p className="text-sm text-gray-600">Upload Date</p>
                <p className="font-semibold">{previewDoc.uploadDate}</p>
              </div>
              <div>
                <p className="text-sm text-gray-600">Status</p>
                <span className={`inline-block px-3 py-1 rounded-full text-sm font-semibold ${getStatusBadge(previewDoc.status)}`}>
                  {previewDoc.status}
                </span>
              </div>
            </div>

            <div className="border-2 border-gray-300 rounded-lg p-8 bg-gray-100 text-center">
              <File size={64} className="mx-auto mb-4 text-gray-400" />
              <p className="text-lg font-semibold mb-2">{previewDoc.fileName}</p>
              <p className="text-sm text-gray-600 mb-4">Preview not available - Document stored securely</p>
              <button
                onClick={() => showNotification('Document downloaded!')}
                className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 font-semibold"
              >
                Download Document
              </button>
            </div>

            {previewDoc.remarks && (
              <div className="mt-4 p-4 bg-yellow-50 border border-yellow-200 rounded-lg">
                <p className="text-sm font-semibold text-gray-700 mb-1">Remarks:</p>
                <p className="text-sm text-gray-600">{previewDoc.remarks}</p>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default EmployeeDocumentSystem;
